            {
              "offset": 1991,
              "length": 119
            }
          ]
        },
        {
          "content": "ifade etmek üzere hacziniz işlenmiştir.",
          "polygon": [
            {
              "x": 0.4877,
              "y": 9.5518
            },
            {
              "x": 2.6006,
              "y": 9.5565
            },
            {
              "x": 2.6003,
              "y": 9.6997
            },
            {
