              "x": 5.8334,
              "y": 10.3151
            },
            {
              "x": 0.5112,
              "y": 10.3154
            }
          ],
          "spans": [
            {
              "offset": 2868,
              "length": 155
            }
          ]
        },
        {
          "content": "5 Yatırım hesabında yer alan fonların değerinin günlük olarak değiştiği ve hisse senetleri karşılığında borsa fiyatına bağlı olarak değişebilir olduğu, fiilen nezdimizde bulunmayan sadece kaydi olarak tutulan söz konusu",
          "polygon": [
            {
              "x": 0.5114,
              "y": 10.3116
            },
            {
              "x": 7.771,
              "y": 10.3121
            },
            {
              "x": 7.771,
              "y": 10.4173
            },
            {
              "x": 0.5114,
              "y": 10.4168
            }
          ],
          "spans": [
            {
              "offset": 3024,
              "length": 219
            }
          ]
        },
        {
          "content": "fonların (Fonlar Merkezi Kayıt Kuruluşu nezdinde saklanmaktadır.) paraya çevrilmesi halinde değerinin satış anındaki borsa fiyatına göre belirleneceğini ve vergi, fon vb. gibi yasal yükümlülüklerin kesileceğini",
          "polygon": [
            {
              "x": 0.4915,
              "y": 10.4134
            },
            {
              "x": 7.7734,
              "y": 10.4136
            },
